let purchasePro = null;
function triggerPurchase(){
	const elmBtns = document.querySelectorAll(".extra-popup .btn-add,.extra-popup .btn-close,.extra-popup .btn-cancel");
	elmBtns.forEach(btn => {
		btn.addEventListener("click", (e) => {
			
			
			if(localStorage.getItem("orderInfo")) return; // case Credit card
			e.preventDefault();
			e.stopImmediatePropagation();
			e.stopPropagation();	
          	const elmParent = e.currentTarget.closest(".extra-popup");
			elmParent && elmParent.classList.remove("popup_widget--opened");
			document.querySelector("body").style.overflow = "auto";
			
			let formatPrice = '';
			let totalPrice = 0;
			const mainShippingPrice = window.ctrwowCheckout.checkoutData.getProduct().shippings[window.shippingIndex || 0].price;
			const mainPrice = window.ctrwowCheckout.checkoutData.getProduct().productPrices.DiscountedPrice.Value;
			totalPrice = mainShippingPrice + mainPrice;
			formatPrice = window.ctrwowUtils.number.formaterNumberByFormattedValue(totalPrice, window.ctrwowCheckout.checkoutData.getProduct().productPrices.DiscountedPrice.FormattedValue);
			let mini = [];
			if(e.currentTarget.classList.contains("btn-add")){
				let purchaseIDs = document.querySelector(".extra-popup").getAttribute("use-pid");
				const mainPid = window.ctrwowCheckout.checkoutData.getProduct().productId;
				let purchaseID = null;
				if (typeof JSON.parse(purchaseIDs) === 'object') {
					purchaseIDs = JSON.parse(purchaseIDs);
					purchaseID = purchaseIDs[mainPid];
				} else {
					purchaseID = purchaseIDs;
				}
				
				purchasePro = window.miniUpsells.find(item => {
					return item.productId.toString() === purchaseID.toString();
				})
				
				mini = window.ctrwowCheckout.checkoutData.getMiniUpsell() || [];
				mini.push({
					productId: purchasePro.productId,
					shippingMethodId: purchasePro.shippings && purchasePro.shippings.length > 0 ? purchasePro.shippings[0].shippingMethodId : null,
					price: purchasePro.productPrices.DiscountedPrice.Value,
					type: 'mini',
					addToSummary: false
				});
				window.ctrwowCheckout.checkoutData.setMiniUpsell(mini);
			}
			
			const btnPP = document.querySelector(".go-to-section-2");
			btnPP && btnPP.click();
			
			mini.forEach(item => {
				totalPrice += item.price;
			})
			
			formatPrice = window.ctrwowUtils.number.formaterNumberByFormattedValue(totalPrice, window.ctrwowCheckout.checkoutData.getProduct().productPrices.DiscountedPrice.FormattedValue);
			
			const totalChooses = document.querySelectorAll(".total-price-choose");
			Array.prototype.slice.call(totalChooses).forEach(item => {
				item.innerText = formatPrice;
			});
		})
	})
	
	const btnCancelPP = document.querySelector(".go-to-section-1");
	btnCancelPP && btnCancelPP.addEventListener("click", function(){
		// remove purchase if cancel
		if(!purchasePro) return;
		let mini = window.ctrwowCheckout.checkoutData.getMiniUpsell() || [];
		mini = mini.filter(item => {
			return item.productId !== purchasePro.productId;
		})
		window.ctrwowCheckout.checkoutData.setMiniUpsell(mini);
		purchasePro = null;
	});
	
	const btnLoginPP = document.querySelector(".login-pp");
	btnLoginPP && btnLoginPP.addEventListener("click", function(){
		window._q('.extra-popup') && window._q('.extra-popup').classList.remove("extra-popup");
	})
}

triggerPurchase();

window.ctrwowUtils.getDependencies([window.ctrwowUtils.getCtrLibLink('ctrwowCheckout')
], {delayUntilInteract: false}).then(() => window.ctrwowCheckout.ready().then(()=> {
	window.PubSub.subscribe('checkoutWithCreditCardV1', (msg, paymentInfo) => {
		if(paymentInfo.customer && document.querySelector("body").classList.contains("paypal-purchase")){
			window._q('.extra-popup') && window._q('.extra-popup').classList.remove("extra-popup"); //remove purchase popup for second time
			const ppLoading = document.querySelector(".ph__paypalButton__predefinedData .paymentProccessing");
          	ppLoading && (ppLoading.style.display = "block");
          	const btnRealCC = document.querySelector("button.creditcard-submit-button");
          	const elmLoading = btnRealCC.parentElement.querySelector(".paymentProccessing");
            elmLoading && (elmLoading .style.zIndex = "9998");
            elmLoading && elmLoading.classList.add("js-hidden");
		}
   })
}))
// End detect purchase popup for PP
;